import os
import secrets
import requests
from functools import wraps
from flask import Flask, redirect, request, session, url_for, jsonify, abort
from jose import jwt, JWTError
from urllib.parse import urlencode

app = Flask(__name__)
app.secret_key = os.environ.get("FLASK_SECRET_KEY", secrets.token_hex(32))

# OIDC Configuration - set these via environment variables
OIDC_CONFIG = {
    "issuer": os.environ.get("OIDC_ISSUER", "https://idp.example.com"),
    "authorization_endpoint": os.environ.get(
        "OIDC_AUTH_ENDPOINT", "https://idp.example.com/authorize"
    ),
    "jwks_uri": os.environ.get(
        "OIDC_JWKS_URI", "https://idp.example.com/.well-known/jwks.json"
    ),
    "client_id": os.environ.get("OIDC_CLIENT_ID", "admin-dashboard-client"),
    "redirect_uri": os.environ.get(
        "OIDC_REDIRECT_URI", "http://localhost:5000/callback"
    ),
}

_jwks_cache = None


def get_jwks():
    """Fetch and cache the JWKS from the identity provider."""
    global _jwks_cache
    if _jwks_cache is None:
        response = requests.get(OIDC_CONFIG["jwks_uri"], timeout=10)
        response.raise_for_status()
        _jwks_cache = response.json()
    return _jwks_cache


def validate_id_token(id_token):
    """
    Validate the ID token signature, issuer, audience, expiry, and nonce.
    Returns the decoded claims if valid, raises an exception otherwise.
    """
    jwks = get_jwks()

    try:
        # Decode and verify the token
        claims = jwt.decode(
            id_token,
            jwks,
            algorithms=["RS256"],
            audience=OIDC_CONFIG["client_id"],
            issuer=OIDC_CONFIG["issuer"],
        )
    except JWTError as e:
        raise ValueError(f"ID token validation failed: {e}")

    # Verify nonce matches what we stored in the session
    expected_nonce = session.get("oidc_nonce")
    if not expected_nonce:
        raise ValueError("No nonce found in session - possible replay or session issue")

    token_nonce = claims.get("nonce")
    if not token_nonce:
        raise ValueError("ID token missing nonce claim")

    if not secrets.compare_digest(str(token_nonce), str(expected_nonce)):
        raise ValueError("Nonce mismatch - possible token replay attack")

    # Clear the nonce after successful validation (single use)
    session.pop("oidc_nonce", None)

    return claims


def login_required(f):
    """Decorator to require authentication for routes."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if "user" not in session:
            session["next_url"] = request.url
            return redirect(url_for("login"))
        return f(*args, **kwargs)
    return decorated_function


@app.route("/")
def index():
    """Public landing page."""
    if "user" in session:
        return redirect(url_for("dashboard"))
    return """
    <html>
    <head><title>Admin Dashboard SSO</title></head>
    <body>
        <h1>Internal Admin Dashboard</h1>
        <p><a href="/login">Login with SSO</a></p>
    </body>
    </html>
    """


@app.route("/login")
def login():
    """Initiate the OIDC authentication flow."""
    # Generate a cryptographically secure nonce and state
    nonce = secrets.token_urlsafe(32)
    state = secrets.token_urlsafe(32)

    # Store nonce and state in session for validation during callback
    session["oidc_nonce"] = nonce
    session["oidc_state"] = state

    # Build the authorization URL
    params = {
        "client_id": OIDC_CONFIG["client_id"],
        "redirect_uri": OIDC_CONFIG["redirect_uri"],
        "scope": "openid",
        "response_type": "id_token",
        "nonce": nonce,  # REQUIRED for implicit flow - prevents token replay attacks
        "state": state,  # CSRF protection
        "response_mode": "fragment",
    }

    authorization_url = f"{OIDC_CONFIG['authorization_endpoint']}?{urlencode(params)}"
    return redirect(authorization_url)


@app.route("/callback")
def callback():
    """
    Handle the OIDC callback.

    For response_type=id_token, the token is returned in the URL fragment
    (after #), which is not sent to the server. We need a small JS page
    to extract it and POST it to our server.

    If using response_mode=form_post, the token comes as a POST parameter.
    """
    # Check if this is a form_post response
    id_token = request.form.get("id_token") or request.args.get("id_token")

    if id_token:
        return _process_id_token(id_token)

    # For fragment-based responses, serve a page that extracts the token
    # from the URL fragment and sends it to the server
    return """
    <html>
    <head><title>Processing login...</title></head>
    <body>
        <p>Processing your login, please wait...</p>
        <script>
            // Extract the ID token from the URL fragment
            const fragment = window.location.hash.substring(1);
            const params = new URLSearchParams(fragment);
            const idToken = params.get('id_token');
            const state = params.get('state');

            if (idToken) {
                // POST the token to the server for validation
                const form = document.createElement('form');
                form.method = 'POST';
                form.action = '/callback/process';

                const tokenInput = document.createElement('input');
                tokenInput.type = 'hidden';
                tokenInput.name = 'id_token';
                tokenInput.value = idToken;
                form.appendChild(tokenInput);

                const stateInput = document.createElement('input');
                stateInput.type = 'hidden';
                stateInput.name = 'state';
                stateInput.value = state || '';
                form.appendChild(stateInput);

                document.body.appendChild(form);
                form.submit();
            } else {
                document.body.innerHTML = '<p>Error: No ID token received. ' +
                    '<a href="/login">Try again</a></p>';
            }
        </script>
        <noscript>
            <p>JavaScript is required for authentication. Please enable it.</p>
        </noscript>
    </body>
    </html>
    """


@app.route("/callback/process", methods=["POST"])
def callback_process():
    """Process the ID token posted from the callback page."""
    id_token = request.form.get("id_token")
    state = request.form.get("state")

    if not id_token:
        abort(400, description="Missing ID token")

    # Validate state parameter (CSRF protection)
    expected_state = session.get("oidc_state")
    if not expected_state or not state:
        abort(400, description="Missing state parameter")

    if not secrets.compare_digest(str(state), str(expected_state)):
        abort(403, description="Invalid state parameter - possible CSRF attack")

    session.pop("oidc_state", None)

    return _process_id_token(id_token)


def _process_id_token(id_token):
    """Validate the ID token and establish a session."""
    try:
        claims = validate_id_token(id_token)
    except ValueError as e:
        app.logger.warning(f"Token validation failed: {e}")
        abort(401, description=f"Authentication failed: {e}")

    # Store user info in session
    session["user"] = {
        "sub": claims.get("sub"),
        "email": claims.get("email"),
        "name": claims.get("name", claims.get("preferred_username", "Unknown")),
        "groups": claims.get("groups", []),
    }

    app.logger.info(
        f"User authenticated: {session['user']['sub']} ({session['user'].get('email')})"
    )

    # Redirect to the originally requested page or dashboard
    next_url = session.pop("next_url", url_for("dashboard"))
    return redirect(next_url)


@app.route("/dashboard")
@login_required
def dashboard():
    """Protected admin dashboard."""
    user = session["user"]
    return f"""
    <html>
    <head><title>Admin Dashboard</title></head>
    <body>
        <h1>Admin Dashboard</h1>
        <p>Welcome, {user.get('name', 'User')}!</p>
        <p>Email: {user.get('email', 'N/A')}</p>
        <p>Subject: {user.get('sub')}</p>
        <p><a href="/profile">Profile</a> | <a href="/logout">Logout</a></p>
    </body>
    </html>
    """


@app.route("/profile")
@login_required
def profile():
    """Display user profile information."""
    return jsonify(session["user"])


@app.route("/logout")
def logout():
    """Clear the session and log the user out."""
    user_sub = session.get("user", {}).get("sub", "unknown")
    session.clear()
    app.logger.info(f"User logged out: {user_sub}")
    return redirect(url_for("index"))


